	@Test
	void plannerCapturesRawSelectedRowsBeforeGroupEnrichment() {
		Value condition = VF.createIRI("urn:test:Condition");
		Value medication = VF.createIRI("urn:test:Medication");
		Value codeA = VF.createLiteral("DX-A");
		Value codeB = VF.createLiteral("DX-B");
		Value codeC = VF.createLiteral("DX-C");
		BindingSetAssignment logicalProduct = new BindingSetAssignment();
		logicalProduct.setBindingNames(Set.of("type", "code"));
		List<BindingSet> rows = new ArrayList<>();
		for (Value type : List.of(condition, medication)) {
			for (Value code : List.of(codeA, codeB, codeC)) {
				MapBindingSet row = new MapBindingSet(2);
				row.addBinding("type", type);
				row.addBinding("code", code);
				rows.add(row);
			}
		}
		logicalProduct.setBindingSets(rows);
		CascadesCostModel costModel = new SelectedRowsCostModel();
		RuleRegistry registry = RuleRegistry.builder()
				.add(new NarrowSelectedRowsImplementationRule(condition, medication))
				.build();

		CascadesPlan plan = new CascadesPlanner(costModel, registry, CascadesTelemetry.NO_OP)
				.optimize(logicalProduct, OptimizationGoal.root());

		Winner winner = plan.winner().orElseThrow();
		assertEquals(6.0d, winner.cost().rows(), 0.0d,
				"The equivalence group keeps its canonical six-row logical output");
		assertEquals(2.0d, winner.selectedOutputRows(), 0.0d,
				"Parent prefix costing must see the two rows produced by the selected physical expression");
		assertEquals(Set.of("type"), winner.selectedOutputNames());
	}

