	@Test
	void strongerEquivalentOutputEvidenceRecostsSiblingsAndParent() {
		StatementPattern code = pattern("cond", "code", "condCode");
		Filter filteredCode = new Filter(code,
				literalListMember("condCode", "DX-200", "DX-201", "DX-202"));
		Projection root = new Projection(filteredCode, projection("cond", "condCode"), false);
		OptimizationGoal goal = OptimizationGoal.root();
		CascadesPlan finiteRuleFirst = equivalentEvidencePlan(root, goal, true);
		CascadesPlan finiteRuleLast = equivalentEvidencePlan(root, goal, false);

		for (CascadesPlan plan : List.of(finiteRuleFirst, finiteRuleLast)) {
			assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness(), plan.diagnostics().toString());
			assertTrue(plan.pendingTasks().isEmpty(), plan.pendingTasks().toString());
			Winner winner = plan.winner().orElseThrow();
			Projection selected = assertInstanceOf(Projection.class, winner.plan());
			assertEquals(3, bindingRows(selected.getArg(), "condCode"),
					() -> "The strongest group output evidence must recost every equivalent sibling and its parent: "
							+ selected);
		}
		assertEquals(finiteRuleFirst.winner().orElseThrow().cost(), finiteRuleLast.winner().orElseThrow().cost(),
				"Canonical equivalent-expression evidence must make registration order irrelevant");
	}

	@Test
	void zeroConfidencePhysicalEstimateDoesNotBecomeSharedLogicalFact() {
		StatementPattern root = pattern("patient", "hasEncounter", "encounter");
		CascadesPlan selectiveFirst = weakEstimatePlan(root, true, 0.0d, 0.0d);
		CascadesPlan inflatedFirst = weakEstimatePlan(root, false, 0.0d, 0.0d);

		for (CascadesPlan plan : List.of(selectiveFirst, inflatedFirst)) {
			assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness(), plan.diagnostics().toString());
			Winner winner = plan.winner().orElseThrow();
			assertEquals(12_504.0d, winner.cost().rows(), 0.0d,
					"A zero-confidence physical estimate must remain local to its implementation");
			assertEquals(12_504.0d, winner.cost().workRows(), 0.0d);
		}
		assertEquals(selectiveFirst.winner().orElseThrow().cost(), inflatedFirst.winner().orElseThrow().cost(),
				"Weak alternative registration order must not change the selected implementation");
	}

