	private CascadesPlan weakEstimatePlan(StatementPattern root, boolean selectiveFirst, double confidence,
			double evidenceCount) {
		RuleRegistry.Builder registry = RuleRegistry.builder();
		if (selectiveFirst) {
			registry.add(new WeakEstimateImplementationRule("weak-selective", 12_504.0d, confidence, evidenceCount));
		}
		registry.add(new WeakEstimateImplementationRule("weak-inflated", 620_961_144.0d, confidence, evidenceCount));
		if (!selectiveFirst) {
			registry.add(new WeakEstimateImplementationRule("weak-selective", 12_504.0d, confidence, evidenceCount));
		}
		return new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry.build(),
				CascadesTelemetry.NO_OP)
					.optimize(root.clone(), OptimizationGoal.root());
	}

	private CascadesPlan equivalentEvidencePlan(Projection root, OptimizationGoal goal, boolean finiteRuleFirst) {
		RuleRegistry.Builder registry = RuleRegistry.builder();
		if (finiteRuleFirst) {
			registry.add(new FiniteFilterJoinAlternativeRule());
		}
		registry.add(new StandardCascadesRules.GenericImplementationRule());
		if (!finiteRuleFirst) {
			registry.add(new FiniteFilterJoinAlternativeRule());
		}
		return new CascadesPlanner(new EquivalentOutputEvidenceCostModel(), registry.build(), CascadesTelemetry.NO_OP)
				.optimize(root.clone(), goal);
	}

	@Test
	void proofOnlyLogicalMergeReactivatesConsumerAndRefreshesParentProvenance() {
		AtomicInteger successfulApplications = new AtomicInteger();
		Filter root = new Filter(pattern("s", "p", "o"), new Bound(new Var("o")));
		RuleRegistry registry = RuleRegistry.builder()
				.add(new ProofDependentConsumerRule(successfulApplications))
				.add(new StructuralDuplicateProofProducerRule())
				.add(new StandardCascadesRules.GenericImplementationRule())
				.build();
		CascadesPlanner planner = new CascadesPlanner(
				new ProofDerivedCostModel(CascadesCostModel.from(new EvaluationStatistics())), registry,
				CascadesTelemetry.NO_OP);

		CascadesPlan plan = planner.optimize(root, OptimizationGoal.root());

		assertEquals(1, successfulApplications.get(),
				"A consumer that first matches after a proof-only merge must fire exactly once");
		MemoExpr parentExpression = plan.memo()
				.group(plan.rootGroupId())
				.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.filter(expression -> expression.tupleExpr() instanceof Filter)
				.findFirst()
				.orElseThrow();
		MemoGroup childGroup = plan.memo().group(parentExpression.inputGroupIds().getFirst());
		MemoExpr derived = childGroup.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.filter(expression -> expression.tupleExpr() instanceof ProofDerivedStatementPattern)
				.findFirst()
				.orElseThrow();
		assertTrue(derived.proofs()
				.stream()
				.anyMatch(proof -> "structural-duplicate-proof-producer".equals(proof.ruleId())),
				"The derived alternative must retain the proof that activated its consumer");
		assertTrue(derived.proofs()
				.stream()
				.anyMatch(proof -> "proof-dependent-consumer".equals(proof.ruleId())),
				"The derived alternative must retain its own rewrite provenance");

		Winner winner = plan.winner().orElseThrow();
		assertTrue(winner.proofs()
				.stream()
				.anyMatch(proof -> "structural-duplicate-proof-producer".equals(proof.ruleId())),
				"A parent winner selected through the derived child must not retain stale proof provenance");
		assertTrue(winner.proofs()
				.stream()
				.anyMatch(proof -> "proof-dependent-consumer".equals(proof.ruleId())));
		PlanProvenance childProvenance = winner.provenance().inputs().getFirst();
		assertEquals(ProofDerivedStatementPattern.class.getSimpleName(), childProvenance.operator());
		assertTrue(childProvenance.proofs()
				.stream()
				.anyMatch(proof -> "proof-dependent-consumer".equals(proof.ruleId())),
				"The selected child's nested provenance must be rebuilt after proof-driven derivation");
	}

	@Test
	void exactSaturationIsIndependentOfRuleRegistrationOrder() {
		AtomicInteger forwardAttempts = new AtomicInteger();
		AtomicInteger reverseAttempts = new AtomicInteger();
		RuleRegistry forward = RuleRegistry.builder()
				.add(new MemoDependencyConsumerRule(forwardAttempts, new AtomicInteger()))
				.add(new TrueFilterDependencyProducerRule())
				.add(new StandardCascadesRules.GenericImplementationRule())
				.build();
		RuleRegistry reverse = RuleRegistry.builder()
				.add(new StandardCascadesRules.GenericImplementationRule())
				.add(new TrueFilterDependencyProducerRule())
				.add(new MemoDependencyConsumerRule(reverseAttempts, new AtomicInteger()))
				.build();
		CascadesCostModel costModel = CascadesCostModel.from(new EvaluationStatistics());

		CascadesPlan forwardPlan = new CascadesPlanner(costModel, forward, CascadesTelemetry.NO_OP)
				.optimize(new Filter(pattern("s", "p", "o"), new ValueConstant(VF.createLiteral(true))),
						OptimizationGoal.root());
		CascadesPlan reversePlan = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), reverse,
				CascadesTelemetry.NO_OP)
						.optimize(new Filter(pattern("s", "p", "o"), new ValueConstant(VF.createLiteral(true))),
								OptimizationGoal.root());

		assertTrue(memoContainsProof(forwardPlan, "memo-dependency-consumer"));
		assertTrue(memoContainsProof(reversePlan, "memo-dependency-consumer"));
		Set<String> forwardExpressions = new HashSet<>(forwardPlan.memo()
				.group(forwardPlan.rootGroupId())
				.expressions()
				.stream()
				.map(MemoExpr::structuralKey)
				.toList());
		Set<String> reverseExpressions = new HashSet<>(reversePlan.memo()
				.group(reversePlan.rootGroupId())
				.expressions()
				.stream()
				.map(MemoExpr::structuralKey)
				.toList());
		assertEquals(forwardExpressions, reverseExpressions);
		assertTrue(forwardAttempts.get() >= 2);
		assertTrue(reverseAttempts.get() >= 2);
	}

