	@Test
	void structuredTelemetryCapturesMatchedAndSkippedRules() throws Exception {
		RuleRegistry registry = RuleRegistry.builder()
				.add(new TestImplementationRule("matching-implementation", 1.0d))
				.add(new NeverMatchingRule("never-match"))
				.build();
		CascadesTelemetry.Recording telemetry = new CascadesTelemetry.Recording(64);
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry,
				telemetry);

		planner.optimize(pattern("s", "p", "o"), OptimizationGoal.root());

		Map<String, Object> trace = structuredTrace(telemetry);
		List<Map<String, Object>> ruleEvaluations = traceList(trace, "ruleEvaluations");
		assertTrue(ruleEvaluations.stream()
				.anyMatch(event -> "matching-implementation".equals(event.get("ruleId"))
						&& "matched".equals(event.get("status"))),
				"Expected structured trace to record the rule that matched: " + trace);
		assertTrue(ruleEvaluations.stream()
				.anyMatch(event -> "never-match".equals(event.get("ruleId"))
						&& "not_matched".equals(event.get("status"))),
				"Expected structured trace to record rules that were not run because they did not match: " + trace);

		List<Map<String, Object>> alternatives = traceList(trace, "alternatives");
		assertTrue(alternatives.stream()
				.anyMatch(event -> "matching-implementation".equals(event.get("ruleId"))
						&& "considered".equals(event.get("status"))),
				"Expected structured trace to record considered alternatives: " + trace);
		assertFalse(traceList(trace, "winners").isEmpty(),
				"Expected structured trace to record the chosen winner: " + trace);
	}

	@Test
	void missingInputWinnerTraceIdentifiesFailedInputGoal() {
		Projection projection = new Projection(pattern("s", "p", "o"), projection("o"), false);
		RuleRegistry registry = RuleRegistry.builder()
				.add(new StandardCascadesRules.GenericImplementationRule())
				.build();
		CascadesTelemetry.Recording telemetry = new CascadesTelemetry.Recording(32);
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry,
				telemetry);
		PhysicalProperties excludedChildShape = PhysicalProperties.builder()
				.boundVars(Set.of("s"))
				.build();
		OptimizationGoal goal = new OptimizationGoal(PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS,
				OptimizationGoal.CostPolicy.EXACT, CostVector.INFINITE, Set.of(excludedChildShape),
				OptimizationGoal.SearchMode.EXACT, Long.MAX_VALUE, Integer.MAX_VALUE);

		CascadesPlan plan = planner.optimize(projection, goal);

		String trace = String.join("\n", telemetry.trace());
		assertTrue(trace.contains("reason=missing-input-winner"), trace);
		assertTrue(trace.contains("inputIndex=0"), trace);
		assertTrue(trace.contains("inputGroup="), trace);
		assertTrue(trace.contains("inputGoal="), trace);
		assertTrue(trace.contains("cost-finalized") && trace.contains("status=permanently-infeasible"), trace);
		assertTrue(plan.pendingTasks().isEmpty(),
				"Exact quiescence must finalize permanently infeasible costs instead of reporting pending work");
	}

	@Test
	void deferredCostExpressionWakesAfterChildWinnerRevisionChanges() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		StatementPattern child = pattern("s", "p", "o");
		Filter root = new Filter(child, new Bound(new Var("o")));
		int rootGroupId = memo.intern(root);
		int childGroupId = memo.group(rootGroupId).expressions().getFirst().inputGroupIds().getFirst();
		MemoExpr childPhysical = memo.addPhysicalAlternative(childGroupId, child.clone(), PhysicalProperties.ANY,
				"child-physical", RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of()).orElseThrow();
		MemoExpr parentPhysical = memo.addPhysicalAlternative(rootGroupId, root.clone(), PhysicalProperties.ANY,
				"parent-physical", RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of()).orElseThrow();
		OptimizationGoal goal = OptimizationGoal.root();
		CascadesPlanner.SearchState state = new CascadesPlanner.SearchState(Integer.MAX_VALUE,
				OptimizationGoal.SearchMode.EXACT);
		state.observeStatisticsEpoch(0L);
		state.deferCostWork(memo, parentPhysical, goal, Set.of(childGroupId),
				"missing-input-winner[inputGroup=" + childGroupId + "]");

		assertFalse(state.hasCostWork(), "A deferred cost must remain blocked until a dependency revision changes");
		long winnerRevisionBefore = memo.group(childGroupId).winnerRevision();
		Winner childWinner = new Winner(childPhysical, child.clone(), PhysicalProperties.ANY,
				new CostVector(1, 1, 0, 0, 0, 1, 1), List.of(), false, "");
		assertTrue(memo.addWinner(goal.key(childGroupId), childWinner, 8, true));
		assertTrue(memo.group(childGroupId).winnerRevision() > winnerRevisionBefore);

		state.wakeDeferredCostWork(memo, childGroupId, 0L, "child_winner_changed");

		assertTrue(state.hasCostWork(), "A child winner revision must reactivate its dependent cost expression");
	}

	@Test
	void deferredCostPresenceIsIndexedByGroupAndCanonicalGoal() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		Filter root = new Filter(pattern("s", "p", "o"), new Bound(new Var("o")));
		int rootGroupId = memo.intern(root);
		MemoExpr parentPhysical = memo.addPhysicalAlternative(rootGroupId, root.clone(), PhysicalProperties.ANY,
				"parent-physical", RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of()).orElseThrow();
		OptimizationGoal goal = OptimizationGoal.root();
		CascadesPlanner.SearchState state = new CascadesPlanner.SearchState(Integer.MAX_VALUE,
				OptimizationGoal.SearchMode.EXACT);

		state.deferCostWork(memo, parentPhysical, goal, Set.of(rootGroupId), "blocked");
		state.deferCostWork(memo, parentPhysical, goal, Set.of(rootGroupId), "blocked");

		assertTrue(state.hasDeferredCostWork(rootGroupId, goal));
		assertTrue(state.diagnostics().contains("deferredCostPresenceIndex=1"),
				"Deferred presence checks must use a group/goal index instead of scanning every deferred expression");
		assertTrue(state.diagnostics().contains("deferredCostRecordsCreated=1"),
				"Repeatedly observing the same blocked state must not rebuild its record or subscriptions");

		state.resolveDeferredCostWork(parentPhysical, goal);

		assertFalse(state.hasDeferredCostWork(rootGroupId, goal));
		assertTrue(state.diagnostics().contains("deferredCostPresenceIndex=0"));
	}

