	@Test
	void unrelatedContextualWinnerDoesNotWakeDeferredCostButExactBlockerDoes() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		Filter root = new Filter(pattern("s", "parentPredicate", "o"), new Bound(new Var("o")));
		int rootGroupId = memo.intern(root);
		MemoExpr parentPhysical = memo.addPhysicalAlternative(rootGroupId, root.clone(), PhysicalProperties.ANY,
				"parent-physical", RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of()).orElseThrow();
		StatementPattern blocker = pattern("x", "contextualBlockerPredicate", "y");
		int blockerGroupId = memo.intern(blocker);
		MemoExpr blockerPhysical = memo.addPhysicalAlternative(blockerGroupId, blocker.clone(), PhysicalProperties.ANY,
				"blocker-physical", RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of()).orElseThrow();
		MapBindingSet bindingsA = new MapBindingSet(1);
		bindingsA.addBinding("seed", VF.createLiteral("a"));
		MapBindingSet bindingsB = new MapBindingSet(1);
		bindingsB.addBinding("seed", VF.createLiteral("b"));
		InputBindingContext contextA = InputBindingContext.fromBindingSet(bindingsA);
		InputBindingContext contextB = InputBindingContext.fromBindingSet(bindingsB);
		OptimizationGoal goalA = OptimizationGoal.root().withInputBindingContext(contextA);
		OptimizationGoal goalB = OptimizationGoal.root().withInputBindingContext(contextB);
		CascadesPlanner.SearchState state = new CascadesPlanner.SearchState(Integer.MAX_VALUE,
				OptimizationGoal.SearchMode.EXACT);
		state.observeStatisticsEpoch(0L);
		state.deferCostWork(memo, parentPhysical, goalA, Set.of(blockerGroupId), "context-a-blocker");

		Winner winnerB = new Winner(blockerPhysical, blocker.clone(), PhysicalProperties.ANY,
				new CostVector(1, 1, 0, 0, 0, 1, 1), List.of(), false, "", null, contextB);
		assertTrue(memo.addWinner(goalB.key(blockerGroupId), winnerB, 8, true));
		state.wakeDeferredCostWork(memo, blockerGroupId, 0L, "context-b-winner-changed");

		assertFalse(state.hasCostWork(), "A winner for context B must not reactivate work blocked on context A");
		assertTrue(state.diagnostics().contains("deferredCostRecordsCreated=1"),
				"An unrelated contextual winner must not rebuild the deferred record");

		Winner winnerA = new Winner(blockerPhysical, blocker.clone(), PhysicalProperties.ANY,
				new CostVector(1, 1, 0, 0, 0, 1, 1), List.of(), false, "", null, contextA);
		assertTrue(memo.addWinner(goalA.key(blockerGroupId), winnerA, 8, true));
		state.wakeDeferredCostWork(memo, blockerGroupId, 0L, "context-a-winner-changed");

		assertTrue(state.hasCostWork(), "The exact contextual blocker revision must reactivate deferred work");
	}

