	@Test
	void supportedCompositeWithoutImplementationDoesNotSeedOpaqueFallback() {
		Projection projection = new Projection(pattern("s", "p", "o"), projection("o"), false);
		RuleRegistry registry = RuleRegistry.builder()
				.add(new StandardCascadesRules.GenericImplementationRule(
						tupleExpr -> tupleExpr instanceof StatementPattern))
				.build();
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry,
				CascadesTelemetry.NO_OP);

		CascadesPlan plan = planner.optimize(projection, OptimizationGoal.root());

		assertTrue(plan.winner().isEmpty(),
				"A missing composite implementation must be reported instead of silently cloning the logical tree");
		assertEquals(OptimizationCompleteness.NO_VIABLE_PHYSICAL_PLAN, plan.completeness());
		assertTrue(plan.memo()
				.groups()
				.stream()
				.flatMap(group -> group.expressions().stream())
				.flatMap(expression -> expression.proofs().stream())
				.noneMatch(proof -> "existing-algebra-emergency-fallback".equals(proof.ruleId())));
		assertTrue(plan.memo()
				.group(plan.rootGroupId())
				.expressions()
				.stream()
				.noneMatch(expression -> expression.physical()
						&& expression.tupleExpr() instanceof Projection
						&& expression.inputGroupIds().isEmpty()),
				"A composite physical expression must never erase its optimizable child group");
		assertTrue(plan.memo()
				.groups()
				.stream()
				.flatMap(group -> group.expressions().stream())
				.anyMatch(expression -> expression.physical()
						&& expression.tupleExpr() instanceof StatementPattern
						&& expression.proofs()
								.stream()
								.anyMatch(proof -> "generic-physical-implementation".equals(proof.ruleId()))),
				"The supported leaf must retain its legitimate physical implementation");
	}

