	@Test
	void transparentMemoTemplateDiscardsExecutableChildTelemetry() {
		StatementPattern child = pattern("s", "p", "o");
		child.setDoubleMetricPlanned("optimizer.testChildRows", 42.0d);
		child.setStringMetricActual("optimizer.testChildActual", "selected-child");
		child.setQueryModelMetadata("test-child-metadata", "selected-child");
		Projection projection = new Projection(child, projection("o"), false);
		projection.setStringMetricPlanned("optimizer.testRoot", "projection-root");
		projection.setQueryModelMetadata("test-root-metadata", "projection-root");
		RuleRegistry registry = RuleRegistry.builder()
				.add(new StandardCascadesRules.GenericImplementationRule())
				.build();

		CascadesPlan plan = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry,
				CascadesTelemetry.NO_OP).optimize(projection, OptimizationGoal.root());
		Projection template = plan.memo()
				.group(plan.rootGroupId())
				.expressions()
				.stream()
				.filter(MemoExpr::physical)
				.map(MemoExpr::tupleExpr)
				.filter(Projection.class::isInstance)
				.map(Projection.class::cast)
				.findFirst()
				.orElseThrow();
		Projection selected = assertInstanceOf(Projection.class, plan.tupleExpr().orElseThrow());

		assertAll(
				() -> assertEquals("projection-root",
						template.getStringMetricPlanned("optimizer.testRoot")),
				() -> assertEquals("projection-root",
						template.getQueryModelMetadata("test-root-metadata")),
				() -> assertTrue(template.getArg().getDoubleMetricsPlanned().isEmpty(),
						"The memo-local child is only a replaceable group placeholder"),
				() -> assertTrue(template.getArg().getStringMetricsActual().isEmpty(),
						"Runtime telemetry must not be retained on a placeholder subtree"),
				() -> assertNull(template.getArg().getQueryModelMetadata("test-child-metadata")),
				() -> assertEquals(42.0d,
						selected.getArg().getDoubleMetricPlanned("optimizer.testChildRows")),
				() -> assertEquals("selected-child",
						selected.getArg().getStringMetricActual("optimizer.testChildActual")),
				() -> assertEquals("selected-child",
						selected.getArg().getQueryModelMetadata("test-child-metadata")));
	}

