	@Test
	void specializedPhysicalRuleCannotClaimScalarSubqueryLocalOutput() {
		StatementPattern outer = pattern("entity", "outerPredicate", "value");
		StatementPattern subquery = pattern("probeLocal", "probePredicate", "probeValue");
		Filter filter = new Filter(outer, new Exists(subquery));
		RuleRegistry registry = RuleRegistry.builder()
				.add(new ScalarLocalLeakingImplementationRule())
				.add(new StandardCascadesRules.GenericImplementationRule(tupleExpr -> !(tupleExpr instanceof Filter)))
				.build();
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry,
				CascadesTelemetry.NO_OP);

		CascadesPlan plan = planner.optimize(filter, OptimizationGoal.root());
		Winner winner = plan.winner().orElseThrow();

		assertEquals(Set.of("entity", "outerPredicate", "value"), winner.deliveredProperties().boundVars());
		assertFalse(winner.deliveredProperties().distinctVars().contains("probeLocal"));
		assertFalse(winner.deliveredProperties().ordering().contains("probeLocal"));

		PhysicalProperties impossibleRequirement = PhysicalProperties.builder()
				.boundVars(Set.of("probeLocal"))
				.build();
		CascadesPlan impossible = planner.optimize(filter.clone(), OptimizationGoal.exact(impossibleRequirement));
		assertTrue(impossible.winner().isEmpty(),
				"A specialized declaration must not turn a scalar-subquery local into a winner output");
	}

