	@Test
	void orderProjectionTransposeRejectsMissingOrAliasedOrderDependencies() {
		Projection missingOrderKey = new Projection(
				new Order(pattern("s", "p", "o"), new OrderElem(new Var("p"))), projection("o"), false);
		assertFalse(hasRuleApplication(missingOrderKey, "order-projection-transpose"),
				"ORDER cannot move above a projection that removes an ordering dependency");

		ProjectionElemList alias = new ProjectionElemList();
		alias.addElement(new ProjectionElem("o", "alias"));
		Projection aliasedOrderKey = new Projection(
				new Order(pattern("s", "p", "o"), new OrderElem(new Var("o"))), alias, false);
		assertFalse(hasRuleApplication(aliasedOrderKey, "order-projection-transpose"),
				"ORDER cannot move across an alias that changes the ordering expression's visible name");

		Projection subqueryBoundary = new Projection(
				new Order(pattern("s", "p", "o"), new OrderElem(new Var("o"))), projection("o"), true);
		assertFalse(hasRuleApplication(subqueryBoundary, "order-projection-transpose"),
				"A subquery projection remains a semantic boundary even when its names look like an identity projection");
	}

	@Test
	void orderProjectionRulesRespectExactObservationSequenceRequirement() {
		Projection projectedOrder = new Projection(
				new Order(pattern("s", "p", "o"), new OrderElem(new Var("o"))), projection("o"), false);
		Distinct distinct = new Distinct(projectedOrder.clone());
		OptimizationGoal exactSequence = OptimizationGoal.root().withRequiredProperties(PhysicalProperties.builder()
				.observationOrder(PhysicalProperties.ObservationOrder.EXACT_SEQUENCE)
				.build());

		assertFalse(hasRuleApplication(projectedOrder, exactSequence, "order-projection-transpose"),
				"Transposition must not change an otherwise unordered serializable observation sequence");
		assertFalse(hasRuleApplication(distinct, exactSequence, "distinct-ordered-projection-reduce"),
				"DISTINCT lowering must remain disabled when the exact observation sequence is required");
	}

	@Test
	void exactObservationSequenceGoalRetainsAnExecutableOriginalWinner() {
		Projection projectedOrder = new Projection(
				new Order(pattern("s", "p", "o"), new OrderElem(new Var("o"))), projection("o"), false);
		OptimizationGoal exactSequence = OptimizationGoal.root().withRequiredProperties(PhysicalProperties.builder()
				.observationOrder(PhysicalProperties.ObservationOrder.EXACT_SEQUENCE)
				.build());

		CascadesPlan plan = planner().optimize(projectedOrder, exactSequence);

		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness());
		Winner winner = plan.winner().orElseThrow();
		assertEquals(PhysicalProperties.ObservationOrder.EXACT_SEQUENCE,
				winner.deliveredProperties().observationOrder());
		Projection selectedProjection = assertInstanceOf(Projection.class, plan.tupleExpr().orElseThrow());
		assertInstanceOf(Order.class, selectedProjection.getArg(),
				"The original Projection(Order(...)) must remain executable under the exact-sequence goal");
		assertFalse(memoContainsProof(plan, "order-projection-transpose"));
	}

