	@Test
	void redundantProjectionRemovalUsesPossibleAndAssuredChildBindings() {
		MapBindingSet complete = new MapBindingSet();
		complete.addBinding("s", VF.createIRI("urn:subject:complete"));
		complete.addBinding("p", VF.createIRI("urn:predicate:complete"));
		complete.addBinding("o", VF.createLiteral("complete"));
		MapBindingSet nullable = new MapBindingSet();
		nullable.addBinding("s", VF.createIRI("urn:subject:nullable"));
		nullable.addBinding("o", VF.createLiteral("nullable"));
		BindingSetAssignment rows = new BindingSetAssignment();
		rows.setBindingSets(List.of(complete, nullable));

		Projection redundant = new Projection(rows.clone(), projection("s", "p", "o"), false);
		CascadesPlan redundantPlan = planner().optimize(redundant, OptimizationGoal.root(redundant,
				PhysicalProperties.ANY));

		assertEquals(OptimizationCompleteness.COMPLETE, redundantPlan.completeness());
		assertInstanceOf(BindingSetAssignment.class, redundantPlan.tupleExpr().orElseThrow());
		assertTrue(memoContainsProof(redundantPlan, "redundant-projection-removal"));

		Projection narrowing = new Projection(rows.clone(), projection("o"), false);
		CascadesPlan narrowingPlan = planner().optimize(narrowing, OptimizationGoal.root(narrowing,
				PhysicalProperties.ANY));

		assertInstanceOf(Projection.class, narrowingPlan.tupleExpr().orElseThrow());
		assertFalse(memoContainsProof(narrowingPlan, "redundant-projection-removal"));
	}

	@Test
	void redundantProjectionRemovalRejectsAliasesAndSemanticBoundaries() {
		BindingSetAssignment rows = wideValues(2);
		ProjectionElemList aliasedNames = new ProjectionElemList();
		aliasedNames.addElement(new ProjectionElem("s", "subject"));
		aliasedNames.addElement(new ProjectionElem("p"));
		aliasedNames.addElement(new ProjectionElem("o"));
		Projection alias = new Projection(rows.clone(), aliasedNames, false);
		Projection subquery = new Projection(rows.clone(), projection("s", "p", "o"), true);
		Projection context = new Projection(rows.clone(), projection("s", "p", "o"), false);
		context.setProjectionContext(new Var("context"));
		Projection scopeChange = new Projection(rows.clone(), projection("s", "p", "o"), false);
		scopeChange.setVariableScopeChange(true);
		StructuralCascadesRules.RedundantProjectionRemovalRule rule =
				new StructuralCascadesRules.RedundantProjectionRemovalRule();

		assertAll(
				() -> assertTrue(apply(rule, alias).isEmpty()),
				() -> assertTrue(apply(rule, subquery).isEmpty()),
				() -> assertTrue(apply(rule, context).isEmpty()),
				() -> assertTrue(apply(rule, scopeChange).isEmpty()));
	}

	@Test
	void projectionPushdownKeepsOuterProjectionAndSharedJoinVars() {
		BindingSetAssignment selectedNames = values("assemblyName");
		Join nameLookup = new Join(new Projection(pattern("assembly", "name", "assemblyName"),
				projection("assembly", "assemblyName"), false), pattern("assembly", "kind", "kind"));
		Projection selectAssembly = new Projection(new Join(selectedNames, nameLookup), projection("assembly"), false);

		Optional<Projection> maybeProjection = apply(new StandardCascadesRules.ProjectionPushdownRule(),
				selectAssembly).stream()
						.map(RuleApplication::alternative)
						.filter(Projection.class::isInstance)
						.map(Projection.class::cast)
						.findFirst();

		assertTrue(maybeProjection.isPresent(), "Projection pushdown must keep the outer projection");
		Projection pushedProjection = maybeProjection.get();
		assertEquals(Set.of("assembly"), pushedProjection.getBindingNames(),
				"The outer projection keeps SELECT-visible bindings only");
		assertTrue(pushedProjection.getArg() instanceof Join);
		Join pushedJoin = (Join) pushedProjection.getArg();
		assertTrue(pushedJoin.getLeftArg().getBindingNames().contains("assemblyName"));
		assertTrue(pushedJoin.getRightArg().getBindingNames().contains("assemblyName"),
				"Shared join variables must remain visible on both inputs after child projection pushdown");
		assertFalse(pushedJoin.getRightArg().getBindingNames().contains("kind"),
				"Unneeded child-only bindings can be pruned under the retained outer projection");
	}

	@Test
	void nestedFilterMergeCombinesConditionsWithoutCrossingScope() {
		Bound leftCondition = new Bound(new Var("s"));
		Bound rightCondition = new Bound(new Var("o"));
		Filter nested = new Filter(new Filter(pattern("s", "p", "o"), leftCondition), rightCondition);

		List<RuleApplication> applications = apply(new StructuralCascadesRules.NestedFilterMergeRule(), nested);

		assertTrue(applications.stream()
				.map(RuleApplication::alternative)
				.anyMatch(alternative -> alternative instanceof Filter filter
						&& filter.getArg() instanceof StatementPattern
						&& filter.getCondition() instanceof And),
				"Expected nested non-scoped filters to merge into a single conjunctive filter");

		nested.setVariableScopeChange(true);
		assertTrue(apply(new StructuralCascadesRules.NestedFilterMergeRule(), nested).isEmpty(),
				"Do not merge across a scope-changing outer filter");

		Filter scopedInner = new Filter(pattern("s", "p", "o"), leftCondition);
		scopedInner.setVariableScopeChange(true);
		assertTrue(apply(new StructuralCascadesRules.NestedFilterMergeRule(),
				new Filter(scopedInner, rightCondition)).isEmpty(),
				"Do not merge across a scope-changing inner filter");
	}

	@Test
	void nestedFilterMergePreservesPositiveExistsBeforeAntiExists() {
		Filter positiveMembership = new Filter(pattern("s", "p", "o"), new Exists(pattern("s", "name", "name")));
		Filter antiProbe = new Filter(positiveMembership, new Not(new Exists(pattern("s", "blockedBy", "blocked"))));

		assertTrue(apply(new StructuralCascadesRules.NestedFilterMergeRule(), antiProbe).isEmpty(),
				"Positive EXISTS filters must stay below anti-EXISTS probes so they can reduce probe input");

		Filter innerAntiProbe = new Filter(pattern("s", "p", "o"),
				new Not(new Exists(pattern("s", "blockedBy", "blocked"))));
		Filter outerPositiveMembership = new Filter(innerAntiProbe, new Exists(pattern("s", "name", "name")));

		assertTrue(apply(new StructuralCascadesRules.NestedFilterMergeRule(), outerPositiveMembership).isEmpty(),
				"Nested filter merge must not combine anti-EXISTS and positive EXISTS in either order");
	}

