	@Test
	void keyOnlyNotExistsToMinusRequiresAssuredSharedKey() {
		Filter disjoint = new Filter(pattern("s", "type", "type"),
				new Not(new Exists(pattern("x", "badFlag", "flag"))));
		assertFalse(applyStandardRules(disjoint).stream()
				.flatMap(application -> application.proofs().stream())
				.anyMatch(proof -> "30".equals(proof.ruleId())),
				"Disjoint NOT EXISTS must not become MINUS");

		Filter filter = new Filter(pattern("s", "type", "type"),
				new Not(new Exists(pattern("s", "badFlag", "flag"))));
		Optional<RuleApplication> maybeMinus = applyStandardRules(filter).stream()
				.filter(application -> application.proofs()
						.stream()
						.anyMatch(proof -> "30".equals(proof.ruleId())
								&& proof.certificate() != null
								&& "30".equals(proof.certificate().ruleId())
								&& proof.certificate().safety().preservedMultiplicity()))
				.findFirst();

		assertTrue(maybeMinus.isPresent(), "Expected rule 30 to build a key-only MINUS alternative");
		assertEquals(RuleKind.IMPLEMENTATION, maybeMinus.orElseThrow().kind(),
				"Key-only materialization must contribute a physical candidate without creating a logical rewrite family");
		TupleExpr alternative = maybeMinus.get().alternative();
		assertTrue(alternative instanceof Difference, "Expected a MINUS/Difference alternative: " + alternative);
		Difference minus = (Difference) alternative;
		assertTrue(containsStatementPattern(minus.getLeftArg(), "s", "type", "type"));
		assertTrue(minus.getRightArg() instanceof Distinct, "Expected distinct anti-join keys: " + minus);
		Distinct distinctKeys = (Distinct) minus.getRightArg();
		assertTrue(distinctKeys.getArg() instanceof Projection, "Expected projected anti-join keys: " + minus);
		Projection keyProjection = (Projection) distinctKeys.getArg();
		assertEquals(Set.of("s"), keyProjection.getProjectionElemList().getProjectedNames());
		assertTrue(containsStatementPattern(keyProjection.getArg(), "s", "badFlag", "flag"));
		assertEquals(PhysicalProperties.Materialization.MATERIALIZED,
				maybeMinus.orElseThrow().inputRequirements().get(1).materialization());
	}

	@Test
	void semanticFamilyClaimsDeduplicateConcreteExpressionsWithoutBlockingNewSemantics() {
		CascadesPlanner.SearchState state = new CascadesPlanner.SearchState(0, OptimizationGoal.SearchMode.EXACT);
		RuleContext context = new RuleContext(null, null, CascadesTelemetry.NO_OP, state);

		assertTrue(context.claimSemanticFamily("key-only-anti-join-materialization", 10, 11, 12, Set.of("enc"),
				SemanticScope.BAG));
		assertFalse(context.claimSemanticFamily("key-only-anti-join-materialization", 10, 11, 12, Set.of("enc"),
				SemanticScope.BAG), "The same semantic expansion must not depend on concrete expression identity");
		assertTrue(context.claimSemanticFamily("key-only-anti-join-materialization", 10, 11, 12,
				Set.of("enc", "patient"), SemanticScope.BAG), "A stronger shared-key contract must reactivate");
		assertTrue(context.claimSemanticFamily("key-only-anti-join-materialization", 20, 11, 12, Set.of("enc"),
				SemanticScope.BAG), "A distinct target equivalence group must remain eligible");
		assertTrue(context.claimSemanticFamily("key-only-anti-join-materialization", 10, 21, 12, Set.of("enc"),
				SemanticScope.BAG), "A distinct left equivalence group must remain eligible");
		assertTrue(context.claimSemanticFamily("key-only-anti-join-materialization", 10, 11, 22, Set.of("enc"),
				SemanticScope.BAG), "A distinct scalar RHS group must remain eligible");
		assertTrue(context.claimSemanticFamily("key-only-anti-join-materialization", 10, 11, 12, Set.of("enc"),
				SemanticScope.SET), "A distinct semantic scope must remain eligible");
	}

