	@Test
	void winnerProvenanceCapturesProofsAndRejectedAlternatives() {
		RuleRegistry registry = RuleRegistry.builder()
				.add(new TestImplementationRule("cheap-rule", 10.0d))
				.add(new TestImplementationRule("expensive-rule", 1_000.0d))
				.build();
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry,
				CascadesTelemetry.NO_OP);

		CascadesPlan plan = planner.optimize(pattern("s", "p", "o"), OptimizationGoal.root());

		Winner winner = plan.winner().orElseThrow();
		PlanProvenance provenance = winner.provenance();
		assertNotNull(provenance);
		assertEquals("cheap-rule", provenance.ruleId());
		assertEquals(RuleKind.IMPLEMENTATION, provenance.ruleKind());
		assertEquals("test-source", provenance.estimate().source());
		assertTrue(provenance.proofs().stream().anyMatch(proof -> "cheap-rule".equals(proof.ruleId())));
		assertFalse(provenance.rejectedAlternatives().isEmpty());
		assertTrue(provenance.rejectedAlternatives()
				.stream()
				.anyMatch(alternative -> "expensive-rule".equals(alternative.ruleId())
						&& "dominated-or-trimmed".equals(alternative.reason())));
	}

