	@Test
	void childSubqueryAlternativeReactivatesParentIntoHashRoute() {
		StatementPattern observations = pattern("patient", "hasObservation", "encounter");
		StatementPattern valueLookup = new StatementPattern(new Var("encounter"),
				new Var("valuePredicate", VF.createIRI("urn:test:valuePredicate")), new Var("value"));
		Join root = new Join(observations, valueLookup);
		RuleRegistry registry = RuleRegistry.builder()
				.add(new NestedBoundaryAlternativeRule())
				.add(new NestedBoundaryDifferenceImplementationRule())
				.add(new StandardCascadesRules.GenericImplementationRule())
				.add(new StandardCascadesRules.HashJoinImplementationRule())
				.add(new StandardCascadesRules.MaterializeEnforcerRule())
				.build();
		CascadesCostModel costModel = new NestedBoundaryAlternativeCostModel(
				CascadesCostModel.from(new EvaluationStatistics()));
		CascadesTelemetry.Recording telemetry = new CascadesTelemetry.Recording(8192);

		CascadesPlan plan = new CascadesPlanner(costModel, registry, telemetry)
				.optimize(root, OptimizationGoal.root());

		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness(), plan.diagnostics().toString());
		Winner winner = plan.winner().orElseThrow();
		Join selected = assertInstanceOf(Join.class, winner.plan());
		assertTrue(selected.getRightArg() instanceof Difference,
				() -> "The cheaper child rewrite must remain available to the generic parent implementation: winner="
						+ winner.cost() + " plan=" + winner.plan() + " diagnostics=" + plan.diagnostics() + "\n"
						+ String.join("\n", telemetry.trace()));
		Difference selectedRight = (Difference) selected.getRightArg();
		Projection selectedBoundary = assertInstanceOf(Projection.class,
				assertInstanceOf(Distinct.class, selectedRight.getRightArg()).getArg());
		assertTrue(selectedBoundary.isSubquery(), "Memo extraction must preserve the nested subquery boundary");
		assertFalse(CascadesRewriteSupport.selectedPrefixInputIsLegal(selectedRight),
				"The assembled RHS is not executable through RDF4J's selected-prefix join route");
		MemoInput rightInput = winner.expression()
				.executableInputs()
				.stream()
				.filter(input -> input.role() == MemoInput.Role.RIGHT)
				.findFirst()
				.orElseThrow();
		assertEquals(PhysicalProperties.InputConsumption.ANY,
				rightInput.requiredProperties().inputConsumption(),
				"A nested subquery forces RDF4J's isolated hash route after the child winner changes shape");
		assertEquals("hash", selected.getStringMetricPlanned("optimizer.joinAlgorithmHint"));
		assertTrue(telemetry.trace()
				.stream()
				.anyMatch(event -> event.contains("selected-prefix-input-route-incompatible")),
				"The stale selected-prefix combination must be rejected explicitly, not hidden by winner dominance");
	}

	@Test
	void inputBindingContextCanonicalizesSourcesAndColumnsWithoutLosingSparseCorrelation() {
		Value entityA = VF.createIRI("urn:medical:entity-a");
		Value entityB = VF.createIRI("urn:medical:entity-b");
		Value targetA = VF.createLiteral("DX-200");
		Value targetB = VF.createLiteral("DX-201");
		FiniteRelationEstimate entityTarget = FiniteRelationEstimate.fromFrequencies(
				List.of("entity", "target"),
				Map.of(List.of(entityA, targetA), 2.0d, List.of(entityB, targetB), 1.0d), "source-a");
		FiniteRelationEstimate targetEntity = FiniteRelationEstimate.fromFrequencies(
				List.of("target", "entity"),
				Map.of(List.of(targetA, entityA), 2.0d, List.of(targetB, entityB), 1.0d), "source-b");
		FiniteRelationEstimate differentCorrelation = FiniteRelationEstimate.fromFrequencies(
				List.of("entity", "target"),
				Map.of(List.of(entityA, targetB), 2.0d, List.of(entityB, targetA), 1.0d), "source-c");

		InputBindingContext first = InputBindingContext.fromProfile(3.0d, Set.of("entity", "target"),
				profile(entityTarget));
		InputBindingContext reordered = InputBindingContext.fromProfile(3.0d, Set.of("target", "entity"),
				profile(targetEntity));
		InputBindingContext sparseAlternative = InputBindingContext.fromProfile(3.0d,
				Set.of("entity", "target"), profile(differentCorrelation));

		assertEquals(first, reordered,
				"Relation source and column order are not part of contextual memo identity");
		assertFalse(first.equals(sparseAlternative),
				"Equal marginal domains must not collapse different sparse tuple correlations");
	}

	@Test
	void equivalentInputContextsCompareWithoutRehashingExactRelationTuples() {
		AtomicInteger forbiddenStructuralAccesses = new AtomicInteger();
		GuardedValue entity = new GuardedValue("urn:medical:entity-a", forbiddenStructuralAccesses);
		GuardedValue target = new GuardedValue("DX-200", forbiddenStructuralAccesses);
		FiniteRelationEstimate relation = FiniteRelationEstimate.fromFrequencies(
				List.of("entity", "target"), Map.of(List.of(entity, target), 1.0d), "medical-values");

		InputBindingContext first = InputBindingContext.fromProfile(1.0d, Set.of("entity", "target"),
				profile(relation));
		InputBindingContext equivalent = InputBindingContext.fromProfile(1.0d, Set.of("target", "entity"),
				profile(relation));
		entity.rejectStructuralAccess();
		target.rejectStructuralAccess();

		assertEquals(first, equivalent,
				"Canonical exact-relation identity must make contextual winner-key comparison independent of tuple size");
		assertEquals(0, forbiddenStructuralAccesses.get(),
				"Comparing an already canonicalized context must not revisit tuple Value equality or hashing");
	}

	private static BindingProfile profile(FiniteRelationEstimate relation) {
		return new BindingProfile(Map.of(), Map.of(VariableSetKey.of(relation.variables()), relation), Map.of(),
				Map.of(), Set.of(), Map.of(), BindingProfile.ANY_ENDPOINT_MODE);
	}

	private static final class GuardedValue implements Value {
		private final String value;
		private final AtomicInteger forbiddenStructuralAccesses;
		private boolean rejectStructuralAccess;

		private GuardedValue(String value, AtomicInteger forbiddenStructuralAccesses) {
			this.value = value;
			this.forbiddenStructuralAccesses = forbiddenStructuralAccesses;
		}

		private void rejectStructuralAccess() {
			rejectStructuralAccess = true;
		}

		@Override
		public String stringValue() {
			return value;
		}

		@Override
		public boolean equals(Object object) {
			if (rejectStructuralAccess) {
				forbiddenStructuralAccesses.incrementAndGet();
				throw new AssertionError("Canonical context equality must not revisit finite-relation tuple values");
			}
			return this == object || object instanceof GuardedValue other && value.equals(other.value);
		}

		@Override
		public int hashCode() {
			if (rejectStructuralAccess) {
				forbiddenStructuralAccesses.incrementAndGet();
				throw new AssertionError("Canonical context equality must not rehash finite-relation tuple values");
			}
			return value.hashCode();
		}
	}

	@Test
	void plannerComposesSelectedChildTotalsWithLocalOperatorCostExactlyOnce() {
		Filter root = new Filter(pattern("s", "p", "o"), new Bound(new Var("o")));
		RuleRegistry registry = RuleRegistry.builder()
				.add(new RecostImplementationRule())
				.build();
		CascadesPlanner planner = new CascadesPlanner(new LocalOnlyCostModel(), registry, CascadesTelemetry.NO_OP);

		Winner winner = planner.optimize(root, OptimizationGoal.root()).winner().orElseThrow();

		assertEquals(3.0d, winner.cost().rows(), 0.0d,
				"Output rows must come from the parent operator estimate, not from summing child rows");
		assertEquals(9.0d, winner.cost().workRows(), 0.0d);
		assertEquals(9.0d, winner.cost().memoryRows(), 0.0d);
		assertEquals(9.0d, winner.cost().seeks(), 0.0d);
		assertEquals(14.0d, winner.cost().pageWalkRows(), 0.0d);
		assertEquals(2.0d, winner.cost().rowQErrorMean(), 0.0d);
		assertEquals(3.0d, winner.cost().rowQErrorMax(), 0.0d);
		assertEquals(78.0d / 9.0d, winner.cost().workQErrorMean(), 0.0d);
		assertEquals(11.0d, winner.cost().workQErrorMax(), 0.0d);
		assertEquals(6.0d, winner.cost().uncertaintyRows(), 0.0d,
				"Parent output uncertainty must not accumulate child output uncertainty");
		assertEquals(0.6d, winner.cost().confidence(), 0.0d);
		assertEquals(20.0d, winner.cost().evidenceCount(), 0.0d);
		assertEquals(1, winner.provenance().inputs().size());
		assertEquals(7.0d, winner.provenance().inputs().getFirst().cost().workRows(), 0.0d,
				"The parent must retain the independently selected child total in provenance");
	}

