	@Test
	void nestedSelectedPrefixCompositeDoesNotLoseOuterContextAndRepeatPopulationTotal() {
		FiniteRelationEstimate finiteValues = FiniteRelationEstimate.fromFrequencies(List.of("value"),
				Map.of(List.<Value>of(VF.createLiteral(50)), 1.0d,
						List.<Value>of(VF.createLiteral(60)), 1.0d,
						List.<Value>of(VF.createLiteral(70)), 1.0d),
				"three-value-context");
		InputBindingContext outerContext = InputBindingContext.fromProfile(3.0d, Set.of("value"),
				profile(finiteValues));
		OptimizationGoal outerGoal = OptimizationGoal.root().withInputBindingContext(outerContext);
		StatementPattern leftPlan = pattern("value", "populationPredicate", "observation");
		Join rightPlan = new Join(values("threshold", VF.createLiteral(50)),
				pattern("observation", "valuePredicate", "threshold"));
		Join parentPlan = new Join(leftPlan, rightPlan);
		PhysicalProperties selectedPrefix = PhysicalProperties.builder()
				.boundVars(Set.of("observation"))
				.inputConsumption(PhysicalProperties.InputConsumption.SELECTED_PREFIX)
				.build();
		PhysicalProperties inputBoundRight = PhysicalProperties.builder()
				.boundVars(Set.of("observation", "threshold"))
				.inputBoundVars(Set.of("observation"))
				.inputConsumption(PhysicalProperties.InputConsumption.SELECTED_PREFIX)
				.build();
		MemoExpr parent = MemoExpr.physical(0, 0, parentPlan, List.of(1, 2), "selected-prefix-parent",
				PhysicalProperties.ANY, List.of(PhysicalProperties.ANY, selectedPrefix), RuleKind.IMPLEMENTATION,
				CostVector.ZERO, List.of(), null);
		MemoExpr left = MemoExpr.physical(1, 1, leftPlan, List.of(), "five-row-left", PhysicalProperties.ANY,
				RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), null);
		MemoExpr right = MemoExpr.physical(2, 2, rightPlan, List.of(3, 4), "context-total-composite",
				inputBoundRight, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), null);
		Winner leftWinner = new Winner(left, leftPlan, PhysicalProperties.ANY, exactCost(5.0d), List.of(), false, "",
				null, outerContext);
		Winner contextlessRightWinner = new Winner(right, rightPlan, inputBoundRight, exactCost(6.0d), List.of(),
				false, "");

		CostVector local = CascadesCostModel.from(new EvaluationStatistics())
				.localCost(parent, outerGoal, List.of(leftWinner, contextlessRightWinner));

		assertTrue(outerGoal.inputBindingContext().isPresent());
		assertEquals(3.0d, outerGoal.inputBindingContext().invocationRows(), 0.0d);
		assertEquals(CostScope.TOTAL_FOR_CONTEXT, leftWinner.costScope());
		assertEquals(InputBindingContext.NONE, contextlessRightWinner.inputBindingContext());
		assertEquals(CostScope.PER_INVOCATION, contextlessRightWinner.costScope());
		assertEquals(6.0d, local.rows(), 0.0d,
				"A nested input-bound composite cannot lose the concrete finite outer context and then repeat its "
						+ "six-row population total for each of the five selected-prefix rows");
	}

	@Test
	void explicitRuleLocalEstimateReplacesCostModelLocalEstimate() {
		Filter root = new Filter(pattern("s", "p", "o"), new Bound(new Var("o")));
		RuleRegistry registry = RuleRegistry.builder()
				.add(new ExplicitLocalCostImplementationRule())
				.build();
		CascadesPlanner planner = new CascadesPlanner(new LocalOnlyCostModel(), registry, CascadesTelemetry.NO_OP);

		Winner winner = planner.optimize(root, OptimizationGoal.root()).winner().orElseThrow();

		assertEquals(3.0d, winner.cost().rows(), 0.0d);
		assertEquals(9.0d, winner.cost().workRows(), 0.0d,
				"A rule-local estimate is an explicit operator estimate, not a second additive pricing channel");
	}

	@Test
	void budgetedParentPrunesInputCombinationsThatCannotBeatIncumbent() {
		Filter root = new Filter(pattern("s", "p", "o"), new Bound(new Var("o")));
		RuleRegistry registry = RuleRegistry.builder()
				.add(new FrontierImplementationRule())
				.build();
		AtomicInteger parentCosts = new AtomicInteger();
		CascadesPlanner planner = new CascadesPlanner(new ConstantParentCostModel(parentCosts), registry,
				CascadesTelemetry.NO_OP);

		CascadesPlan plan = planner.optimize(root, OptimizationGoal.root()
				.asBudgeted(Duration.ofSeconds(1), 256));

		Winner winner = plan.winner().orElseThrow();
		assertEquals(2.0d, winner.cost().workRows(), 0.0d);
		assertEquals(1, parentCosts.get(),
				"Budgeted search should not cost child-frontier combinations whose input work already exceeds the incumbent objective");
	}

	@Test
	void budgetedModeDoesNotBuildPlanForDominatedCandidates() {
		AtomicInteger planBuilds = new AtomicInteger();
		RuleRegistry registry = RuleRegistry.builder()
				.add(new TestImplementationRule("cheap-rule", 1.0d))
				.add(new TestImplementationRule("expensive-rule", 100.0d))
				.build();
		CascadesPlanner planner = new CascadesPlanner(
				new PlanBuildRecordingModel(CascadesCostModel.from(new EvaluationStatistics()), planBuilds),
				registry, CascadesTelemetry.NO_OP);

		CascadesPlan plan = planner.optimize(pattern("s", "p", "o"), OptimizationGoal.root()
				.asBudgeted(Duration.ofSeconds(1), 256));

		assertTrue(plan.winner().isPresent());
		assertEquals("cheap-rule", plan.winner().get().provenance().ruleId());
		assertEquals(1, planBuilds.get(), "Dominated physical candidates should be rejected before cloning a plan");
	}

	private static CascadesPlanner planner() {
		return new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()),
				RuleRegistry.standardLogicalRules(),
				CascadesTelemetry.NO_OP);
	}

	private static List<RuleApplication> apply(CascadesRule rule, TupleExpr tupleExpr) {
		return apply(rule, tupleExpr, null);
	}

	private static List<RuleApplication> apply(CascadesRule rule, TupleExpr tupleExpr, OptimizationGoal goal) {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		int groupId = memo.intern(tupleExpr);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();
		return rule.apply(expression, goal, new RuleContext(memo, null, CascadesTelemetry.NO_OP, null));
	}

	private static List<RuleApplication> applyStandardRules(TupleExpr tupleExpr) {
		return applyStandardRules(tupleExpr, OptimizationGoal.root());
	}

	private static List<RuleApplication> applyStandardRules(TupleExpr tupleExpr, OptimizationGoal goal) {
		return applyStandardRules(tupleExpr, goal, CascadesTelemetry.NO_OP);
	}

	private static List<RuleApplication> applyStandardRules(TupleExpr tupleExpr, OptimizationGoal goal,
			CascadesTelemetry telemetry) {
		CascadesCostModel costModel = CascadesCostModel.from(new EvaluationStatistics());
		Memo memo = new Memo(costModel);
		int groupId = memo.intern(tupleExpr);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();
		RuleContext context = new RuleContext(memo, costModel, telemetry, null);
		return RuleRegistry.standardLogicalRules()
				.applicableRules(expression, goal, memo)
				.stream()
				.flatMap(rule -> rule.apply(expression, goal, context).stream())
				.toList();
	}

	private static List<RuleApplication> applyStandardRules(TupleExpr tupleExpr, OptimizationGoal goal,
			CascadesTelemetry telemetry, RewriteMetadata metadata) {
		CascadesCostModel costModel = CascadesCostModel.from(new EvaluationStatistics());
		Memo memo = new Memo(costModel);
		int groupId = memo.intern(tupleExpr);
		MemoExpr expression = memo.group(groupId).expressions().getFirst();
		RuleContext context = ruleContextWithMetadata(memo, costModel, telemetry, metadata);
		return RuleRegistry.standardLogicalRules()
				.applicableRules(expression, goal, memo)
				.stream()
				.flatMap(rule -> rule.apply(expression, goal, context).stream())
				.toList();
	}

	private static boolean hasRuleApplication(TupleExpr tupleExpr, String ruleId) {
		return hasRuleApplication(tupleExpr, OptimizationGoal.root(), ruleId);
	}

	private static boolean hasRuleApplication(TupleExpr tupleExpr, OptimizationGoal goal, String ruleId) {
		return applyStandardRules(tupleExpr, goal).stream()
				.flatMap(application -> application.proofs().stream())
				.anyMatch(proof -> ruleId.equals(proof.ruleId()));
	}

	private static RuleContext ruleContextWithMetadata(Memo memo, CascadesCostModel costModel,
			CascadesTelemetry telemetry, RewriteMetadata metadata) {
		Optional<Constructor<?>> metadataConstructor = Arrays.stream(RuleContext.class.getConstructors())
				.filter(constructor -> constructor.getParameterCount() == 5)
				.filter(constructor -> constructor.getParameterTypes()[4] == RewriteMetadata.class)
				.findFirst();
		assertTrue(metadataConstructor.isPresent(),
				"RuleContext should carry rewrite metadata for metadata-gated rewrites");
		try {
			return (RuleContext) metadataConstructor.get().newInstance(memo, costModel, telemetry, null, metadata);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError("RuleContext metadata constructor should be usable by rule tests", e);
		}
	}

	private static boolean standardRulesContainValuesAnchor(TupleExpr tupleExpr, String bindingName) {
		return applyStandardRules(tupleExpr)
				.stream()
				.map(RuleApplication::alternative)
				.anyMatch(alternative -> bindingRows(alternative, bindingName) >= 0);
	}

	private static boolean memoContainsProof(CascadesPlan plan, String ruleId) {
		return plan.memo()
				.groups()
				.stream()
				.flatMap(group -> group.expressions().stream())
				.flatMap(expression -> expression.proofs().stream())
				.anyMatch(proof -> ruleId.equals(proof.ruleId()));
	}

	@SuppressWarnings("unchecked")
	private static Map<String, Object> structuredTrace(CascadesTelemetry.Recording telemetry) throws Exception {
		return (Map<String, Object>) CascadesTelemetry.Recording.class
				.getMethod("structuredTrace")
				.invoke(telemetry);
	}

	@SuppressWarnings("unchecked")
	private static List<Map<String, Object>> traceList(Map<String, Object> trace, String key) {
		Object value = trace.get(key);
		assertTrue(value instanceof List, () -> "Expected trace field " + key + " to be a list: " + trace);
		return (List<Map<String, Object>>) value;
	}

	private static ProjectionElemList projection(String... names) {
		ProjectionElemList list = new ProjectionElemList();
		for (String name : names) {
			list.addElement(new ProjectionElem(name));
		}
		return list;
	}

	private static BindingSetAssignment wideValues(int rowCount) {
		List<BindingSet> rows = new ArrayList<>(rowCount);
		for (int index = 0; index < rowCount; index++) {
			MapBindingSet row = new MapBindingSet();
			row.addBinding("s", VF.createIRI("urn:subject:" + index));
			row.addBinding("p", VF.createIRI("urn:predicate:" + index % 4));
			row.addBinding("o", VF.createLiteral(index % 16));
			rows.add(row);
		}
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingSets(rows);
		return assignment;
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}

	private static StatementPattern constantPredicatePattern(String predicate) {
		return new StatementPattern(new Var("s"), new Var("predicate", VF.createIRI(predicate)), new Var("o"));
	}

	private static ListMemberOperator listMember(String variableName, String... iriValues) {
		ListMemberOperator operator = new ListMemberOperator();
		operator.addArgument(new Var(variableName));
		for (String iriValue : iriValues) {
			operator.addArgument(new ValueConstant(VF.createIRI(iriValue)));
		}
		return operator;
	}

	private static ListMemberOperator literalListMember(String variableName, String... literalValues) {
		ListMemberOperator operator = new ListMemberOperator();
		operator.addArgument(new Var(variableName));
		for (String literalValue : literalValues) {
			operator.addArgument(new ValueConstant(VF.createLiteral(literalValue)));
		}
		return operator;
	}

	private static int bindingRows(TupleExpr tupleExpr, String bindingName) {
		if (tupleExpr instanceof BindingSetAssignment assignment
				&& assignment.getBindingNames().contains(bindingName)) {
			int rows = 0;
			for (var ignored : assignment.getBindingSets()) {
				rows++;
			}
			return rows;
		}
		if (tupleExpr instanceof Join join) {
			int leftRows = bindingRows(join.getLeftArg(), bindingName);
			return leftRows >= 0 ? leftRows : bindingRows(join.getRightArg(), bindingName);
		}
		return -1;
	}

	private static Set<Value> bindingValues(TupleExpr tupleExpr, String bindingName) {
		if (tupleExpr instanceof BindingSetAssignment assignment
				&& assignment.getBindingNames().contains(bindingName)) {
			Set<Value> values = new HashSet<>();
			for (BindingSet bindingSet : assignment.getBindingSets()) {
				if (bindingSet.hasBinding(bindingName)) {
					values.add(bindingSet.getValue(bindingName));
				}
			}
			return values;
		}
		if (tupleExpr instanceof Join join) {
			Set<Value> leftValues = bindingValues(join.getLeftArg(), bindingName);
			return leftValues.isEmpty() ? bindingValues(join.getRightArg(), bindingName) : leftValues;
		}
		return Set.of();
	}

	private static Set<Value> endpointExtensionValues(TupleExpr tupleExpr) {
		if (tupleExpr instanceof Extension extension) {
			Set<Value> values = new HashSet<>();
			for (ExtensionElem element : extension.getElements()) {
				if ("endpoint".equals(element.getName()) && element.getExpr()instanceof ValueConstant constant) {
					values.add(constant.getValue());
				}
			}
			return values;
		}
		if (tupleExpr instanceof Union union) {
			Set<Value> values = new HashSet<>(endpointExtensionValues(union.getLeftArg()));
			values.addAll(endpointExtensionValues(union.getRightArg()));
			return values;
		}
		return Set.of();
	}

	private static Set<Value> fixedServiceRefs(TupleExpr tupleExpr) {
		if (tupleExpr instanceof Service service
				&& service.getServiceRef().hasValue()) {
			return Set.of(service.getServiceRef().getValue());
		}
		if (tupleExpr instanceof Extension extension) {
			return fixedServiceRefs(extension.getArg());
		}
		if (tupleExpr instanceof Union union) {
			Set<Value> values = new HashSet<>(fixedServiceRefs(union.getLeftArg()));
			values.addAll(fixedServiceRefs(union.getRightArg()));
			return values;
		}
		return Set.of();
	}

	private static boolean allServiceBranchesSilent(TupleExpr tupleExpr) {
		if (tupleExpr instanceof Service service) {
			return service.isSilent();
		}
		if (tupleExpr instanceof Extension extension) {
			return allServiceBranchesSilent(extension.getArg());
		}
		if (tupleExpr instanceof Union union) {
			return allServiceBranchesSilent(union.getLeftArg()) && allServiceBranchesSilent(union.getRightArg());
		}
		return false;
	}

	private static boolean containsStatementPattern(TupleExpr tupleExpr, String subject, String predicate,
			String object) {
		if (tupleExpr instanceof StatementPattern pattern) {
			return subject.equals(pattern.getSubjectVar().getName())
					&& predicate.equals(pattern.getPredicateVar().getName())
					&& object.equals(pattern.getObjectVar().getName());
		}
		if (tupleExpr instanceof Join join) {
			return containsStatementPattern(join.getLeftArg(), subject, predicate, object)
					|| containsStatementPattern(join.getRightArg(), subject, predicate, object);
		}
		if (tupleExpr instanceof Extension extension) {
			return containsStatementPattern(extension.getArg(), subject, predicate, object);
		}
		if (tupleExpr instanceof Union union) {
			return containsStatementPattern(union.getLeftArg(), subject, predicate, object)
					|| containsStatementPattern(union.getRightArg(), subject, predicate, object);
		}
		return false;
	}

	private static BindingSetAssignment values(String name) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(Set.of(name));
		MapBindingSet bindingSet = new MapBindingSet(1);
		bindingSet.addBinding(name, VF.createLiteral(name + "-value"));
		assignment.setBindingSets(List.of(bindingSet));
		return assignment;
	}

	private static BindingSetAssignment values(String name, Value... values) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(Set.of(name));
		List<BindingSet> bindingSets = new ArrayList<>();
		for (Value value : values) {
			MapBindingSet bindingSet = new MapBindingSet(1);
			bindingSet.addBinding(name, value);
			bindingSets.add(bindingSet);
		}
		assignment.setBindingSets(bindingSets);
		return assignment;
	}

	private static int countLeftJoins(TupleExpr tupleExpr) {
		if (tupleExpr instanceof LeftJoin) {
			return 1;
		}
		if (tupleExpr instanceof Join join) {
			return countLeftJoins(join.getLeftArg()) + countLeftJoins(join.getRightArg());
		}
		if (tupleExpr instanceof Union union) {
			return countLeftJoins(union.getLeftArg()) + countLeftJoins(union.getRightArg());
		}
		if (tupleExpr instanceof Filter filter) {
			return countLeftJoins(filter.getArg());
		}
		return 0;
	}

	private static boolean containsDiscriminatorFilter(TupleExpr tupleExpr, String name, Value value) {
		if (tupleExpr instanceof Filter filter
				&& filter.getCondition()instanceof SameTerm sameTerm
				&& sameTermMatches(sameTerm, name, value)) {
			return true;
		}
		if (tupleExpr instanceof LeftJoin leftJoin) {
			return containsDiscriminatorFilter(leftJoin.getLeftArg(), name, value)
					|| containsDiscriminatorFilter(leftJoin.getRightArg(), name, value);
		}
		if (tupleExpr instanceof Join join) {
			return containsDiscriminatorFilter(join.getLeftArg(), name, value)
					|| containsDiscriminatorFilter(join.getRightArg(), name, value);
		}
		if (tupleExpr instanceof Union union) {
			return containsDiscriminatorFilter(union.getLeftArg(), name, value)
					|| containsDiscriminatorFilter(union.getRightArg(), name, value);
		}
		return false;
	}

	private static boolean sameTermMatches(SameTerm sameTerm, String name, Value value) {
		return valueEqualsVar(sameTerm.getLeftArg(), sameTerm.getRightArg(), name, value)
				|| valueEqualsVar(sameTerm.getRightArg(), sameTerm.getLeftArg(), name, value);
	}

	private static boolean valueEqualsVar(ValueExpr left, ValueExpr right, String name, Value value) {
		return left instanceof Var var
				&& name.equals(var.getName())
				&& right instanceof ValueConstant constant
				&& value.equals(constant.getValue());
	}

	private static boolean containsDifference(TupleExpr tupleExpr) {
		if (tupleExpr instanceof Difference) {
			return true;
		}
		if (tupleExpr instanceof Filter filter) {
			return containsDifference(filter.getArg());
		}
		if (tupleExpr instanceof Join join) {
			return containsDifference(join.getLeftArg()) || containsDifference(join.getRightArg());
		}
		if (tupleExpr instanceof Union union) {
			return containsDifference(union.getLeftArg()) || containsDifference(union.getRightArg());
		}
		return false;
	}

	private static boolean isNegatedExistsFilter(TupleExpr tupleExpr) {
		return tupleExpr instanceof Filter filter
				&& filter.getCondition()instanceof Not not
				&& not.getArg() instanceof Exists;
	}

	private static boolean containsNegatedExistsFilterWithoutBinding(TupleExpr tupleExpr, String bindingName) {
		if (tupleExpr instanceof Filter filter) {
			return isNegatedExistsFilter(filter) && !containsBindingSetAssignment(filter.getArg(), bindingName)
					|| containsNegatedExistsFilterWithoutBinding(filter.getArg(), bindingName);
		}
		if (tupleExpr instanceof Join join) {
			return containsNegatedExistsFilterWithoutBinding(join.getLeftArg(), bindingName)
					|| containsNegatedExistsFilterWithoutBinding(join.getRightArg(), bindingName);
		}
		if (tupleExpr instanceof Extension extension) {
			return containsNegatedExistsFilterWithoutBinding(extension.getArg(), bindingName);
		}
		if (tupleExpr instanceof Union union) {
			return containsNegatedExistsFilterWithoutBinding(union.getLeftArg(), bindingName)
					|| containsNegatedExistsFilterWithoutBinding(union.getRightArg(), bindingName);
		}
		return false;
	}

	private static boolean containsNegatedExistsFilterAtAssuredPrefix(TupleExpr tupleExpr, String assuredBinding,
			String excludedBinding) {
		if (tupleExpr instanceof Filter filter) {
			if (isNegatedExistsFilter(filter)
					&& filter.getArg().getAssuredBindingNames().contains(assuredBinding)
					&& !filter.getArg().getBindingNames().contains(excludedBinding)) {
				return true;
			}
			return containsNegatedExistsFilterAtAssuredPrefix(filter.getArg(), assuredBinding, excludedBinding);
		}
		if (tupleExpr instanceof Join join) {
			return containsNegatedExistsFilterAtAssuredPrefix(join.getLeftArg(), assuredBinding, excludedBinding)
					|| containsNegatedExistsFilterAtAssuredPrefix(join.getRightArg(), assuredBinding, excludedBinding);
		}
		return false;
	}

	private static boolean containsLocalNegatedFilterOnBranchName(TupleExpr tupleExpr) {
		if (tupleExpr instanceof Filter filter
				&& filter.getCondition() instanceof Not
				&& filter.getArg()instanceof StatementPattern pattern
				&& pattern.getSubjectVar() != null
				&& "branch".equals(pattern.getSubjectVar().getName())
				&& pattern.getObjectVar() != null
				&& "branchName".equals(pattern.getObjectVar().getName())) {
			return true;
		}
		if (tupleExpr instanceof Join join) {
			return containsLocalNegatedFilterOnBranchName(join.getLeftArg())
					|| containsLocalNegatedFilterOnBranchName(join.getRightArg());
		}
		if (tupleExpr instanceof Filter filter) {
			return containsLocalNegatedFilterOnBranchName(filter.getArg());
		}
		return false;
	}

	private static Optional<Union> findScopedUnion(TupleExpr tupleExpr) {
		if (tupleExpr instanceof Union union && union.isVariableScopeChange()) {
			return Optional.of(union);
		}
		if (tupleExpr instanceof Join join) {
			Optional<Union> left = findScopedUnion(join.getLeftArg());
			return left.isPresent() ? left : findScopedUnion(join.getRightArg());
		}
		if (tupleExpr instanceof Extension extension) {
			return findScopedUnion(extension.getArg());
		}
		return Optional.empty();
	}

	private static boolean containsBindingSetAssignment(TupleExpr tupleExpr, String bindingName) {
		if (tupleExpr instanceof BindingSetAssignment assignment) {
			return assignment.getBindingNames().contains(bindingName);
		}
		if (tupleExpr instanceof Join join) {
			return containsBindingSetAssignment(join.getLeftArg(), bindingName)
					|| containsBindingSetAssignment(join.getRightArg(), bindingName);
		}
		if (tupleExpr instanceof Extension extension) {
			return containsBindingSetAssignment(extension.getArg(), bindingName);
		}
		if (tupleExpr instanceof Union union) {
			return containsBindingSetAssignment(union.getLeftArg(), bindingName)
					|| containsBindingSetAssignment(union.getRightArg(), bindingName);
		}
		return false;
	}

	private static boolean containsConnectedFiniteNameGuard(TupleExpr tupleExpr) {
		return containsBindingSetAssignment(tupleExpr, "u")
				&& containsBindingSetAssignment(tupleExpr, "optName")
				&& containsStatementPattern(tupleExpr, "u", "name", "optName");
	}

	private record DependentParentWakeCountingRule(AtomicInteger firstParentAttempts,
			AtomicInteger siblingParentAttempts) implements CascadesRule {

		private static final String ID = "test-dependent-parent-wake-counter";
		private static final String FIRST_PREDICATE = "urn:test:first-parent-child";
		private static final String SIBLING_PREDICATE = "urn:test:sibling-parent-child";
		private static final String COMMON_PREDICATE = "urn:test:common-union-child";
		private static final RuleDescriptor DESCRIPTOR = RuleDescriptor.builder(ID, RuleKind.TRANSFORMATION)
				.rootOperators(RuleRootOperator.UNION)
				.changesProduced()
				.wakeUpEvents(RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED,
						RuleWakeUpEvent.CHILD_EXPRESSION_CHANGED)
				.priority(new RulePriority(RulePhase.CHEAP_LOGICAL, 100))
				.convergenceClass(RuleConvergenceClass.FINITE_EQUIVALENCE_EXPANSION)
				.build();

		@Override
		public String id() {
			return ID;
		}

		@Override
		public RuleKind kind() {
			return RuleKind.TRANSFORMATION;
		}

		@Override
		public RuleDescriptor descriptor() {
			return DESCRIPTOR;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			String predicate = leftUnionPredicate(expression);
			return FIRST_PREDICATE.equals(predicate) || SIBLING_PREDICATE.equals(predicate);
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 100;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			if (FIRST_PREDICATE.equals(leftUnionPredicate(expression))) {
				firstParentAttempts.incrementAndGet();
			} else {
				siblingParentAttempts.incrementAndGet();
			}
			return List.of();
		}
	}

	private static final class EquivalentUnionSiblingRule implements CascadesRule {

		private static final String ID = "test-equivalent-union-sibling";
		private static final RuleDescriptor DESCRIPTOR = RuleDescriptor.builder(ID, RuleKind.TRANSFORMATION)
				.rootOperators(RuleRootOperator.UNION)
				.changesProduced(RuleDescriptor.ProducedChange.LOGICAL_EXPRESSION,
						RuleDescriptor.ProducedChange.PROOF)
				.wakeUpEvents(RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED)
				.priority(new RulePriority(RulePhase.CHEAP_LOGICAL, 80))
				.convergenceClass(RuleConvergenceClass.FINITE_EQUIVALENCE_EXPANSION)
				.build();

		@Override
		public String id() {
			return ID;
		}

		@Override
		public RuleKind kind() {
			return RuleKind.TRANSFORMATION;
		}

		@Override
		public RuleDescriptor descriptor() {
			return DESCRIPTOR;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return DependentParentWakeCountingRule.FIRST_PREDICATE.equals(leftUnionPredicate(expression))
					&& memo.group(expression.groupId())
							.expressions()
							.stream()
							.noneMatch(candidate -> DependentParentWakeCountingRule.SIBLING_PREDICATE
									.equals(leftUnionPredicate(candidate)));
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 80;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			Union union = (Union) expression.tupleExpr();
			Union sibling = new Union(
					constantPredicatePattern(DependentParentWakeCountingRule.SIBLING_PREDICATE),
					union.getRightArg().clone());
			RuleProof proof = new RuleProof(ID, kind(), OptimizationGoal.BAG_SEMANTICS,
					Set.of("testEquivalentSibling"), "Test-only equivalent parent with an independent child group");
			return List.of(RuleApplication.transformation(expression.groupId(), sibling, proof));
		}
	}

	private static final class LateFirstUnionChildRule implements CascadesRule {

		private static final String ID = "test-late-first-union-child";
		private static final String LATE_PREDICATE = "urn:test:late-first-parent-child";
		private static final RuleDescriptor DESCRIPTOR = RuleDescriptor.builder(ID, RuleKind.TRANSFORMATION)
				.rootOperators(RuleRootOperator.UNION)
				.changesProduced(RuleDescriptor.ProducedChange.LOGICAL_EXPRESSION,
						RuleDescriptor.ProducedChange.PROOF)
				.wakeUpEvents(RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED)
				.priority(new RulePriority(RulePhase.CHEAP_LOGICAL, 60))
				.convergenceClass(RuleConvergenceClass.FINITE_EQUIVALENCE_EXPANSION)
				.build();

		@Override
		public String id() {
			return ID;
		}

		@Override
		public RuleKind kind() {
			return RuleKind.TRANSFORMATION;
		}

		@Override
		public RuleDescriptor descriptor() {
			return DESCRIPTOR;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			if (!DependentParentWakeCountingRule.SIBLING_PREDICATE.equals(leftUnionPredicate(expression))) {
				return false;
			}
			return firstParentChildGroup(memo, expression.groupId())
					.stream()
					.mapToObj(memo::group)
					.flatMap(group -> group.expressions().stream())
					.noneMatch(candidate -> LATE_PREDICATE.equals(statementPredicate(candidate.tupleExpr())));
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 60;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			int childGroupId = firstParentChildGroup(context.memo(), expression.groupId()).orElseThrow();
			RuleProof proof = new RuleProof(ID, kind(), OptimizationGoal.BAG_SEMANTICS,
					Set.of("lateChildAlternative"), "Test-only late alternative for the first parent child");
			return List.of(RuleApplication.transformation(childGroupId, constantPredicatePattern(LATE_PREDICATE),
					proof));
		}
	}

	private record LateScopedUnionBranchAlternativeRule(TupleExpr common, TupleExpr rightResidual)
			implements CascadesRule {

		private static final String ID = "test-late-scoped-union-branch-alternative";
		private static final RuleDescriptor DESCRIPTOR = RuleDescriptor.builder(ID, RuleKind.TRANSFORMATION)
				.rootOperators(RuleRootOperator.UNION)
				.changesProduced(RuleDescriptor.ProducedChange.LOGICAL_EXPRESSION,
						RuleDescriptor.ProducedChange.PROOF)
				.wakeUpEvents(RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED)
				.priority(new RulePriority(RulePhase.CHEAP_LOGICAL, 40))
				.convergenceClass(RuleConvergenceClass.FINITE_EQUIVALENCE_EXPANSION)
				.build();

		@Override
		public String id() {
			return ID;
		}

		@Override
		public RuleKind kind() {
			return RuleKind.TRANSFORMATION;
		}

		@Override
		public RuleDescriptor descriptor() {
			return DESCRIPTOR;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			MemoInput leftInput = unionInput(expression, MemoInput.Role.LEFT);
			MemoInput rightInput = unionInput(expression, MemoInput.Role.RIGHT);
			return expression.logical()
					&& expression.tupleExpr() instanceof Union union
					&& union.isVariableScopeChange()
					&& leftInput != null
					&& rightInput != null
					&& memo.group(leftInput.groupId())
							.expressions()
							.stream()
							.filter(MemoExpr::logical)
							.anyMatch(candidate -> candidate.tupleExpr() instanceof Join join
									&& join.getLeftArg().equals(common))
					&& memo.group(rightInput.groupId())
							.expressions()
							.stream()
							.filter(MemoExpr::logical)
							.noneMatch(candidate -> candidate.tupleExpr() instanceof Join join
									&& join.getLeftArg().equals(common)
									&& join.getRightArg().equals(rightResidual));
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 40;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			MemoInput rightInput = unionInput(expression, MemoInput.Role.RIGHT);
			if (rightInput == null) {
				return List.of();
			}
			RuleProof proof = new RuleProof(ID, kind(), OptimizationGoal.BAG_SEMANTICS,
					Set.of("lateChildAlternative", "innerJoinCommutation"),
					"Test-only late reorder in the authoritative scoped UNION right-child group");
			return List.of(RuleApplication.transformation(rightInput.groupId(),
					new Join(common.clone(), rightResidual.clone()), proof));
		}

		private static MemoInput unionInput(MemoExpr expression, MemoInput.Role role) {
			if (expression == null) {
				return null;
			}
			return expression.inputs()
					.stream()
					.filter(input -> input.use() == MemoInput.Use.EXECUTABLE && input.role() == role)
					.findFirst()
					.orElse(null);
		}
	}

	private static OptionalInt firstParentChildGroup(Memo memo, int parentGroupId) {
		return memo.group(parentGroupId)
				.expressions()
				.stream()
				.filter(candidate -> DependentParentWakeCountingRule.FIRST_PREDICATE
						.equals(leftUnionPredicate(candidate)))
				.findFirst()
				.map(candidate -> OptionalInt.of(candidate.inputGroupIds().getFirst()))
				.orElseGet(OptionalInt::empty);
	}

	private static String leftUnionPredicate(MemoExpr expression) {
		return expression != null && expression.logical() && expression.tupleExpr() instanceof Union union
				? statementPredicate(union.getLeftArg())
				: null;
	}

	private static String statementPredicate(TupleExpr tupleExpr) {
		return tupleExpr instanceof StatementPattern pattern && pattern.getPredicateVar().hasValue()
				? pattern.getPredicateVar().getValue().stringValue()
				: null;
	}

