	private record MemoDependencyConsumerRule(AtomicInteger attempts, AtomicInteger successfulApplications)
			implements FiniteTestCascadesRule {

		@Override
		public String id() {
			return "memo-dependency-consumer";
		}

		@Override
		public RuleKind kind() {
			return RuleKind.TRANSFORMATION;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return expression.logical() && expression.tupleExpr() instanceof Filter;
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 100;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			attempts.incrementAndGet();
			boolean dependencyPresent = context.memo()
					.group(expression.groupId())
					.expressions()
					.stream()
					.anyMatch(candidate -> candidate.logical()
							&& candidate.tupleExpr() instanceof StatementPattern);
			if (!dependencyPresent) {
				return List.of();
			}
			boolean alreadyProduced = context.memo()
					.group(expression.groupId())
					.expressions()
					.stream()
					.flatMap(candidate -> candidate.proofs().stream())
					.anyMatch(proof -> id().equals(proof.ruleId()));
			if (alreadyProduced) {
				return List.of();
			}

			successfulApplications.incrementAndGet();
			Filter filter = (Filter) expression.tupleExpr();
			Projection alternative = new Projection(filter.getArg().clone(), projection("s", "p", "o"), false);
			return List.of(RuleApplication.transformation(expression.groupId(), alternative,
					proof(expression, goal, context)));
		}
	}

	private record ChildAlternativeParentConsumerRule(AtomicInteger earlyAttempts,
			AtomicInteger successfulApplications) implements FiniteTestCascadesRule {

		@Override
		public String id() {
			return "child-alternative-parent-consumer";
		}

		@Override
		public RuleKind kind() {
			return RuleKind.TRANSFORMATION;
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return expression.logical() && expression.tupleExpr() instanceof Filter;
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 100;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			MemoGroup parentGroup = context.memo().group(expression.groupId());
			if (parentGroup.physicalRevision() != 0L || parentGroup.winnerRevision() != 0L) {
				return List.of();
			}
			earlyAttempts.incrementAndGet();
			MemoGroup childGroup = context.memo().group(expression.inputGroupIds().getFirst());
			boolean qualifyingAlternative = childGroup.expressions()
					.stream()
					.anyMatch(candidate -> candidate.physical()
							&& "dependency-marker".equals(candidate.deliveredProperties().accessPath()));
			if (!qualifyingAlternative || childGroup.winnerRevision() != 0L) {
				return List.of();
			}
			boolean alreadyProduced = parentGroup.expressions()
					.stream()
					.flatMap(candidate -> candidate.proofs().stream())
					.anyMatch(proof -> id().equals(proof.ruleId()));
			if (alreadyProduced) {
				return List.of();
			}

			successfulApplications.incrementAndGet();
			return List.of(RuleApplication.transformation(expression.groupId(), expression.tupleExpr().clone(),
					proof(expression, goal, context)));
		}
	}

